  private static persistNewCorrection(input: {
    sourceType: CorrectionSource;
    sourceId: string;
    title: string;
    responsible: string;
    dueDate: number;
    progress: number;
    status: CorrectionStatus;
    note: string;
    photos: string[];
  }): Correction {
