    const item: Correction = {
      id: newCorrectionId(),
      sourceType: input.sourceType,
      sourceId: input.sourceId,
      title: input.title,
      responsible: input.responsible,
      dueDate: input.dueDate,
      progress: input.progress,
      status: input.status,
      note: input.note,
      photos: input.photos.slice(),
