  // 内部：更新隐患状态与关联整改 id（不暴露给表单）。
  static setHazardCorrection(id: string, correctionId: string, status: HazardStatus): void {
    const current: Hazard | null = DataStore.getHazard(id);
    if (current === null) {
      return;
    }
    const updated: Hazard = {
      id: current.id,
