// PhoneService.ets
//
// 应急联系人一键拨号（call-contact 流程）。
// 使用系统拨号面板，无需额外授权。失败返回 false，由调用方给出提示。
// ArkTS strict-safe。

import { call } from '@kit.AbilityKit';

export class PhoneService {
  // 发起拨号。phone 应已通过 Validators.isPhoneLike 校验。
  static async makeCall(phone: string): Promise<boolean> {
    if (phone.trim().length === 0) {
      return false;
    }
    try {
      await call.makeCall(phone.trim());
      return true;
    } catch (err) {
      return false;
    }
  }
}

